import json


def parse_json_object(text: str) -> dict[str, object]:
    def build_object(pairs: list[tuple[str, object]]) -> dict[str, object]:
        result: dict[str, object] = {}
        for key, value in pairs:
            if key in result:
                raise ValueError(f"duplicate JSON key: {key}")
            result[key] = value
        return result

    def reject_constant(token: str) -> object:
        raise ValueError(f"invalid JSON number: {token}")

    try:
        value = json.loads(
            text,
            object_pairs_hook=build_object,
            parse_constant=reject_constant,
        )
    except json.JSONDecodeError as exc:
        raise ValueError(f"invalid JSON at line {exc.lineno}, column {exc.colno}") from exc
    if not isinstance(value, dict):
        raise ValueError("JSON root must be an object")
    return value

from pathlib import Path


def list_text_files(directory: Path, suffixes: set[str]) -> list[str]:
    if not directory.is_dir():
        raise NotADirectoryError(directory)
    if any(not suffix.startswith(".") or suffix != suffix.lower() for suffix in suffixes):
        raise ValueError("suffixes must be lowercase and start with a dot")

    names = [
        entry.name
        for entry in directory.iterdir()
        if not entry.is_symlink()
        and entry.is_file()
        and entry.suffix.lower() in suffixes
    ]
    return sorted(names, key=lambda name: (name.casefold(), name))

import hashlib
from pathlib import Path


def sha256_file(path: Path, chunk_size: int = 65536) -> str:
    if isinstance(chunk_size, bool) or not isinstance(chunk_size, int):
        raise TypeError("chunk_size must be an integer")
    if chunk_size <= 0:
        raise ValueError("chunk_size must be positive")

    digest = hashlib.sha256()
    with path.open("rb") as handle:
        while chunk := handle.read(chunk_size):
            digest.update(chunk)
    return digest.hexdigest()

import configparser
from pathlib import Path


def read_ini_section(path: Path, section: str) -> dict[str, str]:
    if not isinstance(section, str) or not section.strip():
        raise ValueError("section must be non-blank")

    parser = configparser.ConfigParser(interpolation=None, strict=True)
    parser.optionxform = str
    with path.open("r", encoding="utf-8") as handle:
        parser.read_file(handle)
    if parser.defaults():
        raise ValueError("DEFAULT values are not allowed")
    if not parser.has_section(section):
        raise KeyError(section)
    return dict(parser.items(section, raw=True))

def decode_utf8_text(data: bytes) -> str:
    if not isinstance(data, bytes):
        raise TypeError("data must be bytes")
    text = data.decode("utf-8-sig", errors="strict")
    return text.replace("\r\n", "\n").replace("\r", "\n")

import math


def require_json_value(value: object) -> object:
    active: set[int] = set()

    def visit(item: object, path: str) -> None:
        if item is None or isinstance(item, (bool, str, int)):
            return
        if isinstance(item, float):
            if not math.isfinite(item):
                raise ValueError(f"{path} contains a non-finite number")
            return
        if isinstance(item, (list, dict)):
            marker = id(item)
            if marker in active:
                raise ValueError(f"{path} contains a reference cycle")
            active.add(marker)
            try:
                if isinstance(item, list):
                    for index, child in enumerate(item):
                        visit(child, f"{path}[{index}]")
                else:
                    for key, child in item.items():
                        if not isinstance(key, str):
                            raise TypeError(f"{path} contains a non-string key")
                        visit(child, f"{path}.{key}")
            finally:
                active.remove(marker)
            return
        raise TypeError(f"{path} contains unsupported type {type(item).__name__}")

    visit(value, "$" )
    return value

def merge_disjoint_objects(
    objects: list[dict[str, object]],
) -> dict[str, object]:
    result: dict[str, object] = {}
    for object_index, item in enumerate(objects):
        if not isinstance(item, dict):
            raise TypeError(f"item {object_index} must be a dict")
        for key, value in item.items():
            if not isinstance(key, str) or not key.strip():
                raise ValueError(f"item {object_index} contains an invalid key")
            if key in result:
                raise ValueError(f"duplicate key: {key}")
            result[key] = value
    return result

export function parseJsonRecord(text: string): Record<string, unknown> {
  let value: unknown;
  try {
    value = JSON.parse(text) as unknown;
  } catch (error) {
    throw new Error("invalid JSON", { cause: error });
  }
  if (value === null || Array.isArray(value) || typeof value !== "object") {
    throw new Error("JSON root must be an object");
  }
  return value as Record<string, unknown>;
}

export function encodeCsvRow(fields: readonly string[]): string {
  return fields
    .map((field) => {
      if (/[",\r\n]/.test(field)) {
        return `"${field.replaceAll('"', '""')}"`;
      }
      return field;
    })
    .join(",");
}

