import { readFile } from "node:fs/promises";

export async function readTextLines(path: string): Promise<string[]> {
  const text = (await readFile(path, "utf8")).replace(/^\uFEFF/, "");
  if (text.length === 0) return [];

  const lines = text.split(/\r\n|\n|\r/);
  if (/(?:\r\n|\n|\r)$/.test(text)) lines.pop();
  return lines;
}

export function parseTwoColumnTsv(text: string): Map<string, string> {
  const result = new Map<string, string>();
  const lines = text.split(/\r\n|\n|\r/);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    if (line === "") continue;
    const firstTab = line.indexOf("\t");
    if (firstTab < 0 || firstTab !== line.lastIndexOf("\t")) {
      throw new Error(`line ${index + 1}: expected exactly two columns`);
    }
    const key = line.slice(0, firstTab).trim();
    const value = line.slice(firstTab + 1);
    if (key === "") throw new Error(`line ${index + 1}: key is blank`);
    if (result.has(key)) throw new Error(`line ${index + 1}: duplicate key ${key}`);
    result.set(key, value);
  }
  return result;
}

export function indexCompositeRows<
  T extends { tenantId: string; id: string },
>(rows: readonly T[]): Map<string, T> {
  const result = new Map<string, T>();
  for (const row of rows) {
    if (row.tenantId.trim() === "" || row.id.trim() === "") {
      throw new Error("tenantId and id must be non-blank");
    }
    const key = JSON.stringify([row.tenantId, row.id]);
    if (result.has(key)) throw new Error("duplicate tenantId/id pair");
    result.set(key, row);
  }
  return result;
}

export function firstCsvHeader(text: string): string[] {
  const clean = text.replace(/^\uFEFF/, "");
  if (clean === "") return [];
  const [firstLine] = clean.split(/\r\n|\n|\r/, 1);
  return firstLine.split(",");
}

