export function mergeConfigLayers(
  layers: readonly Readonly<Record<string, string | undefined>>[],
): Map<string, string> {
  const result = new Map<string, string>();
  for (const layer of layers) {
    for (const [key, value] of Object.entries(layer)) {
      if (key.trim() === "") throw new Error("config keys must be non-blank");
      if (value !== undefined) result.set(key, value);
    }
  }
  return result;
}

function serializeJsonLines(records) {
  if (!Array.isArray(records)) throw new TypeError("records must be an array");
  const lines = records.map((record, index) => {
    if (record === null || Array.isArray(record) || typeof record !== "object") {
      throw new TypeError(`record ${index} must be an object`);
    }
    const encoded = JSON.stringify(record);
    if (encoded === undefined) throw new TypeError(`record ${index} is not serializable`);
    return encoded;
  });
  return lines.length === 0 ? "" : `${lines.join("\n")}\n`;
}

function parseCsvRow(line) {
  if (typeof line !== "string") throw new TypeError("line must be a string");
  if (/[\r\n]/.test(line)) throw new Error("line must contain one physical record");

  const fields = [];
  let field = "";
  let quoted = false;
  let closedQuote = false;

  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    if (quoted) {
      if (char === '"') {
        if (line[index + 1] === '"') {
          field += '"';
          index += 1;
        } else {
          quoted = false;
          closedQuote = true;
        }
      } else {
        field += char;
      }
    } else if (closedQuote) {
      if (char !== ",") throw new Error("unexpected text after closing quote");
      fields.push(field);
      field = "";
      closedQuote = false;
    } else if (char === ",") {
      fields.push(field);
      field = "";
    } else if (char === '"') {
      if (field !== "") throw new Error("quote must start at the beginning of a field");
      quoted = true;
    } else {
      field += char;
    }
  }

  if (quoted) throw new Error("unclosed quoted field");
  fields.push(field);
  return fields;
}

