const { readdir } = require("node:fs/promises");

async function listDirectoryFiles(path) {
  const entries = await readdir(path, { withFileTypes: true });
  return entries
    .filter((entry) => entry.isFile() && !entry.isSymbolicLink())
    .map((entry) => entry.name)
    .sort((left, right) => (left < right ? -1 : left > right ? 1 : 0));
}

function indexRowsByField(rows, field) {
  if (!Array.isArray(rows)) throw new TypeError("rows must be an array");
  if (typeof field !== "string" || field.trim() === "") {
    throw new TypeError("field must be a non-blank string");
  }
  const result = new Map();
  rows.forEach((row, index) => {
    if (row === null || Array.isArray(row) || typeof row !== "object") {
      throw new TypeError(`row ${index} must be an object`);
    }
    if (!Object.hasOwn(row, field) || typeof row[field] !== "string") {
      throw new TypeError(`row ${index} must have own string field ${field}`);
    }
    const key = row[field].trim();
    if (key === "") throw new Error(`row ${index} has a blank key`);
    if (result.has(key)) throw new Error(`duplicate key: ${key}`);
    result.set(key, row);
  });
  return result;
}

function parseJsonStringArray(text) {
  let value;
  try {
    value = JSON.parse(text);
  } catch (error) {
    throw new Error("invalid JSON", { cause: error });
  }
  if (!Array.isArray(value)) throw new Error("JSON root must be an array");
  return value.map((item, index) => {
    if (typeof item !== "string") throw new TypeError(`item ${index} must be a string`);
    const cleaned = item.trim();
    if (cleaned === "") throw new Error(`item ${index} must not be blank`);
    return cleaned;
  });
}

function canonicalFlatJson(record) {
  if (record === null || Array.isArray(record) || typeof record !== "object") {
    throw new TypeError("record must be an object");
  }
  const result = Object.create(null);
  const keys = Object.keys(record).sort((a, b) => (a < b ? -1 : a > b ? 1 : 0));
  for (const key of keys) {
    const value = record[key];
    const valid =
      value === null ||
      typeof value === "string" ||
      typeof value === "boolean" ||
      (typeof value === "number" && Number.isFinite(value));
    if (!valid) throw new TypeError(`unsupported value for key ${key}`);
    result[key] = value;
  }
  return JSON.stringify(result);
}

function Read-Utf8LinesStrict {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $LiteralPath
    )

    $resolved = Resolve-Path -LiteralPath $LiteralPath -ErrorAction Stop
    if (-not [System.IO.File]::Exists($resolved.Path)) {
        throw "Path is not a file: $LiteralPath"
    }
    $utf8 = [System.Text.UTF8Encoding]::new($false, $true)
    return [System.IO.File]::ReadAllLines($resolved.Path, $utf8)
}

function Get-DirectoryFileReport {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $LiteralPath
    )

    $directory = Get-Item -LiteralPath $LiteralPath -ErrorAction Stop
    if (-not $directory.PSIsContainer) {
        throw "Path is not a directory: $LiteralPath"
    }

    Get-ChildItem -LiteralPath $directory.FullName -File -Force |
        Where-Object { -not ($_.Attributes -band [IO.FileAttributes]::ReparsePoint) } |
        Sort-Object Name |
        Select-Object Name, Extension, Length
}

function ConvertTo-JsonLine {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory, ValueFromPipeline)]
        [AllowNull()]
        [object] $InputObject
    )

    process {
        $isRecord = $InputObject -is [System.Collections.IDictionary] -or
            $InputObject -is [pscustomobject]
        if ($null -eq $InputObject -or -not $isRecord -or $InputObject -is [array]) {
            throw "InputObject must be a hashtable or PSCustomObject"
        }
        $InputObject | ConvertTo-Json -Compress -Depth 10
    }
}

function Measure-FileExtension {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory, ValueFromPipeline)]
        [System.IO.FileInfo] $File
    )

    begin { $counts = @{} }
    process {
        $extension = if ([string]::IsNullOrEmpty($File.Extension)) {
            '<none>'
        } else {
            $File.Extension.ToLowerInvariant()
        }
        $counts[$extension] = 1 + [int] $counts[$extension]
    }
    end {
        foreach ($extension in ($counts.Keys | Sort-Object)) {
            [pscustomobject]@{
                Extension = $extension
                Count = $counts[$extension]
            }
        }
    }
}

function Get-FilePreview {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string] $LiteralPath,

        [ValidateRange(1, 100)]
        [int] $Count = 10
    )

    $item = Get-Item -LiteralPath $LiteralPath -ErrorAction Stop
    if ($item.PSIsContainer) {
        throw "Path is not a file: $LiteralPath"
    }
    Get-Content -LiteralPath $item.FullName -Encoding UTF8 -TotalCount $Count
}

